import fs from 'fs';
import path from 'path';

const DATA_DIR = path.join(__dirname, '..', 'data');

interface TradeRecord {
  date: string;
  city: string;
  side: 'YES' | 'NO';
  entry_price: number;
  outcome: 'won' | 'lost';
  pnl_per_contract: number;
}

interface ScenarioResult {
  kellyFraction: number;
  startingBankroll: number;
  finalBankroll: number;
  peakBankroll: number;
  maxDrawdown: number;
  maxDrawdownPct: number;
  totalTrades: number;
  winRate: number;
  roi: number;
  ruined: boolean;
  sharpeRatio: number;
  bankrollCurve: number[];
  avgPositionSizePct: number;
  avgContractsBought: number;
  capped: boolean; // whether maxContracts/maxPositionPct caps were applied
}

function estimatePWin(side: 'YES' | 'NO', entryPrice: number): number {
  if (side === 'NO' && entryPrice > 0.85) return 0.75;
  if (side === 'YES') return Math.min(0.75, Math.max(0.50, 0.50 + (0.55 - entryPrice) * 0.8));
  return 0.60;
}

function runKellyBacktest(
  trades: TradeRecord[],
  kellyFraction: number,
  startingBankroll: number,
  maxContracts: number = 9999,
  maxPositionPct: number = 1.0
): ScenarioResult {
  let bankroll = startingBankroll;
  let peak = startingBankroll;
  let maxDrawdown = 0;
  let maxDrawdownPct = 0;
  let ruined = false;
  const bankrollCurve: number[] = [startingBankroll];
  const tradeReturns: number[] = [];
  const positionSizes: number[] = [];
  const contractCounts: number[] = [];
  let won = 0;

  for (const trade of trades) {
    if (bankroll <= 0) { ruined = true; break; }

    const pWin = estimatePWin(trade.side, trade.entry_price);
    const odds = (1 / trade.entry_price) - 1;
    const rawKelly = (pWin * odds - (1 - pWin)) / odds;
    if (rawKelly <= 0) { bankrollCurve.push(bankroll); continue; }

    const fraction = rawKelly * kellyFraction;
    const maxByPct = bankroll * maxPositionPct;
    const dollarSize = Math.min(fraction * bankroll, maxByPct);
    const rawContracts = Math.floor(dollarSize / trade.entry_price);
    const contracts = Math.max(1, Math.min(maxContracts, rawContracts));
    const cost = contracts * trade.entry_price;
    const pnl = contracts * trade.pnl_per_contract;

    positionSizes.push(cost / bankroll);
    contractCounts.push(contracts);
    tradeReturns.push(pnl / bankroll);

    bankroll += pnl;
    if (trade.outcome === 'won') won++;

    if (bankroll > peak) peak = bankroll;
    const drawdown = peak - bankroll;
    const drawdownPct = drawdown / peak;
    if (drawdown > maxDrawdown) maxDrawdown = drawdown;
    if (drawdownPct > maxDrawdownPct) maxDrawdownPct = drawdownPct;
    if (bankroll < startingBankroll * 0.1) ruined = true;

    bankrollCurve.push(Math.round(bankroll * 100) / 100);
  }

  const mean = tradeReturns.length > 0 ? tradeReturns.reduce((a, b) => a + b, 0) / tradeReturns.length : 0;
  const variance = tradeReturns.length > 1
    ? tradeReturns.reduce((s, r) => s + Math.pow(r - mean, 2), 0) / tradeReturns.length
    : 1;
  const sharpeRatio = variance > 0 ? mean / Math.sqrt(variance) : 0;

  return {
    kellyFraction,
    startingBankroll,
    finalBankroll: Math.round(bankroll * 100) / 100,
    peakBankroll: Math.round(peak * 100) / 100,
    maxDrawdown: Math.round(maxDrawdown * 100) / 100,
    maxDrawdownPct: Math.round(maxDrawdownPct * 1000) / 1000,
    totalTrades: trades.length,
    winRate: trades.length > 0 ? won / trades.length : 0,
    roi: (bankroll - startingBankroll) / startingBankroll,
    ruined,
    sharpeRatio: Math.round(sharpeRatio * 1000) / 1000,
    bankrollCurve,
    avgPositionSizePct: positionSizes.length > 0 ? positionSizes.reduce((a, b) => a + b, 0) / positionSizes.length : 0,
    avgContractsBought: contractCounts.length > 0 ? contractCounts.reduce((a, b) => a + b, 0) / contractCounts.length : 0,
    capped: maxContracts < 9999 || maxPositionPct < 1.0,
  };
}

