  const settled = tradesRaw.filter((t: any) => t.status === 'won' || t.status === 'lost');

  const trades: TradeRecord[] = settled.map((t: any) => ({
    date: t.target_date,
    city: t.city,
    side: t.side,
    entry_price: t.entry_price,
    outcome: t.status,
    pnl_per_contract: t.status === 'won' ? (1 - t.entry_price) : -t.entry_price,
  }));

  const kellyFractions = [0.10, 0.15, 0.25, 0.50, 1.0];
  const bankrolls = [500, 1000, 2000, 5000];
  const scenarios: ScenarioResult[] = [];

  // Uncapped scenarios
  for (const kf of kellyFractions) {
    for (const br of bankrolls) {
      scenarios.push(runKellyBacktest(trades, kf, br, 9999, 1.0));
    }
  }

  // Capped scenarios (max 100 contracts, 10% bankroll per trade)
  for (const kf of kellyFractions) {
    for (const br of bankrolls) {
