import { useEffect, useState, useMemo } from 'react'
import { LineChart, Line, XAxis, YAxis, CartesianGrid, Tooltip, Legend, ResponsiveContainer } from 'recharts'

interface ScenarioResult {
  kellyFraction: number
  startingBankroll: number
  finalBankroll: number
  peakBankroll: number
  maxDrawdown: number
  maxDrawdownPct: number
  totalTrades: number
  winRate: number
  roi: number
  ruined: boolean
  sharpeRatio: number
  bankrollCurve: number[]
  avgPositionSizePct: number
  avgContractsBought: number
  capped: boolean
}

interface KellyData {
  runDate: string
  tradeCount: number
  winRate: number
  scenarios: ScenarioResult[]
  optimal: ScenarioResult
  recommendation: {
    kellyFraction: number
    startingBankroll: number
    expectedGrowthPct: number
    maxExpectedDrawdown: number
    reasoning: string
  }
}

type SortKey = 'kellyFraction' | 'startingBankroll' | 'finalBankroll' | 'roi' | 'maxDrawdownPct' | 'sharpeRatio'

const KELLY_COLORS: Record<string, string> = {
  '10': '#06b6d4',
  '15': '#22c55e',
  '25': '#eab308',
  '50': '#f97316',
  '100': '#ef4444',
}

export default function KellyOptimizer({ api }: { api: string }) {
  const [data, setData] = useState<KellyData | null>(null)
  const [loading, setLoading] = useState(true)
  const [running, setRunning] = useState(false)
  const [error, setError] = useState<string | null>(null)
  const [sortKey, setSortKey] = useState<SortKey>('roi')
  const [sortAsc, setSortAsc] = useState(false)

  const fetchData = () => {
    setLoading(true)
    fetch(`${api}/api/kelly-backtest`)
      .then(r => r.json())
      .then(d => { if (d.error) setError(d.error); else setData(d) })
      .catch(e => setError(e.message))
      .finally(() => setLoading(false))
  }

  useEffect(() => { fetchData() }, [api])

  const runBacktest = async () => {
    setRunning(true)
    setError(null)
    try {
      const r = await fetch(`${api}/api/kelly-backtest/run`, { method: 'POST' })
      const d = await r.json()
      if (d.error) setError(d.error)
      else setData(d)
    } catch (e: any) {
      setError(e.message)
    } finally {
      setRunning(false)
    }
  }

  const handleSort = (key: SortKey) => {
    if (sortKey === key) setSortAsc(!sortAsc)
    else { setSortKey(key); setSortAsc(false) }
  }

  // Optimal bankroll curve chart data
  const optimalCurveData = useMemo(() => {
    if (!data?.optimal) return []
    return data.optimal.bankrollCurve.map((v, i) => ({ trade: i, bankroll: v }))
  }, [data])

  // Comparison chart: all Kelly fractions at $1000 uncapped
  const comparisonData = useMemo(() => {
    if (!data?.scenarios) return []
    const series = data.scenarios.filter(s => s.startingBankroll === 1000 && !s.capped)
    if (series.length === 0) return []
    const maxLen = Math.max(...series.map(s => s.bankrollCurve.length))
    const rows: Record<string, number>[] = []
    for (let i = 0; i < maxLen; i++) {
      const row: Record<string, number> = { trade: i }
      for (const s of series) {
        const label = `${(s.kellyFraction * 100).toFixed(0)}%`
        row[label] = i < s.bankrollCurve.length ? s.bankrollCurve[i] : s.bankrollCurve[s.bankrollCurve.length - 1]
      }
      rows.push(row)
    }
    return rows
  }, [data])

  const comparisonKeys = useMemo(() => {
    if (comparisonData.length === 0) return []
    return Object.keys(comparisonData[0]).filter(k => k !== 'trade')
  }, [comparisonData])

  // Sorted scenarios for table
  const sortedScenarios = useMemo(() => {
    if (!data?.scenarios) return []
    const arr = [...data.scenarios]
    arr.sort((a, b) => {
      const av = a[sortKey] as number
      const bv = b[sortKey] as number
      return sortAsc ? av - bv : bv - av
    })
    return arr
  }, [data, sortKey, sortAsc])

  if (loading) return <div className="text-slate-400">Loading Kelly backtest data...</div>

  if (!data) return (
    <div className="bg-slate-800 rounded-xl border border-slate-700 px-6 py-12 text-center">
      <p className="text-4xl mb-3">🎯</p>
      <p className="text-slate-300">No Kelly backtest data yet</p>
      {error && <p className="text-red-400 text-sm mt-2">{error}</p>}
      <button onClick={runBacktest} disabled={running}
        className="mt-4 px-4 py-2 bg-sky-600 hover:bg-sky-500 disabled:bg-slate-600 rounded-lg text-sm font-medium transition-colors">
        {running ? '⏳ Running...' : '🚀 Run Backtest'}
      </button>
    </div>
  )

  const opt = data.optimal
  const rec = data.recommendation

  return (
    <div className="space-y-6">
      {/* Header */}
      <div className="flex items-center justify-between">
        <h2 className="text-lg font-semibold text-white">Kelly Criterion Optimizer</h2>
        <div className="flex items-center gap-3">
          <span className="text-slate-400 text-sm">Run: {data.runDate} | {data.tradeCount} trades</span>
          <button onClick={runBacktest} disabled={running}
            className="px-4 py-2 bg-sky-600 hover:bg-sky-500 disabled:bg-slate-600 rounded-lg text-sm font-medium transition-colors">
            {running ? '⏳ Running...' : '🔄 Re-run'}
          </button>
        </div>
      </div>

      {error && <div className="bg-red-900/30 border border-red-700 rounded-lg px-4 py-2 text-red-300 text-sm">{error}</div>}

      {/* Recommendation cards */}
      <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
        {[
          { label: 'Optimal Kelly %', value: `${(opt.kellyFraction * 100).toFixed(0)}%`, sub: opt.capped ? 'capped' : 'uncapped' },
          { label: 'Starting Bankroll', value: `$${opt.startingBankroll.toLocaleString()}`, sub: `→ $${opt.finalBankroll.toLocaleString()}` },
          { label: 'Growth', value: `${(opt.roi * 100).toFixed(1)}%`, positive: opt.roi > 0 },
          { label: 'Max Drawdown', value: `${(opt.maxDrawdownPct * 100).toFixed(1)}%`, positive: opt.maxDrawdownPct < 0.2 },
        ].map(c => (
          <div key={c.label} className="bg-slate-800 rounded-xl border border-slate-700 px-5 py-4">
            <p className="text-slate-400 text-xs">{c.label}</p>
            <p className={`text-2xl font-bold mt-1 ${c.positive === undefined ? 'text-white' : c.positive ? 'text-emerald-400' : 'text-red-400'}`}>{c.value}</p>
            {'sub' in c && c.sub && <p className="text-slate-500 text-xs mt-1">{c.sub}</p>}
          </div>
        ))}
      </div>

      {/* Reasoning */}
      <div className="bg-slate-800 rounded-xl border border-slate-700 px-5 py-4">
        <p className="text-slate-400 text-xs mb-1">Recommendation</p>
        <p className="text-slate-200 text-sm">{rec.reasoning}</p>
        <div className="mt-2 flex gap-4 text-xs text-slate-500">
          <span>Win rate: {(data.winRate * 100).toFixed(1)}%</span>
          <span>Sharpe: {opt.sharpeRatio}</span>
          <span>Avg contracts: {opt.avgContractsBought.toFixed(1)}</span>
          <span>Avg position: {(opt.avgPositionSizePct * 100).toFixed(1)}%</span>
        </div>
      </div>

      {/* Optimal bankroll curve */}
      <div className="bg-slate-800 rounded-xl border border-slate-700 p-5">
        <h3 className="text-sm font-medium text-slate-300 mb-4">Optimal Scenario — Bankroll Curve</h3>
        <ResponsiveContainer width="100%" height={300}>
          <LineChart data={optimalCurveData}>
            <CartesianGrid strokeDasharray="3 3" stroke="#334155" />
            <XAxis dataKey="trade" stroke="#94a3b8" tick={{ fontSize: 12 }} label={{ value: 'Trade #', position: 'insideBottom', offset: -5, fill: '#94a3b8' }} />
            <YAxis stroke="#94a3b8" tick={{ fontSize: 12 }} tickFormatter={v => `$${v}`} />
            <Tooltip contentStyle={{ backgroundColor: '#1e293b', border: '1px solid #475569', borderRadius: 8 }} labelFormatter={v => `Trade #${v}`} formatter={(v: number) => [`$${v.toFixed(2)}`, 'Bankroll']} />
            <Line type="monotone" dataKey="bankroll" stroke="#22c55e" strokeWidth={2} dot={false} />
          </LineChart>
        </ResponsiveContainer>
      </div>

      {/* Comparison chart */}
      {comparisonData.length > 0 && (
        <div className="bg-slate-800 rounded-xl border border-slate-700 p-5">
          <h3 className="text-sm font-medium text-slate-300 mb-4">Kelly Fraction Comparison — $1,000 Bankroll (Uncapped)</h3>
          <ResponsiveContainer width="100%" height={300}>
            <LineChart data={comparisonData}>
              <CartesianGrid strokeDasharray="3 3" stroke="#334155" />
              <XAxis dataKey="trade" stroke="#94a3b8" tick={{ fontSize: 12 }} label={{ value: 'Trade #', position: 'insideBottom', offset: -5, fill: '#94a3b8' }} />
              <YAxis stroke="#94a3b8" tick={{ fontSize: 12 }} tickFormatter={v => `$${v}`} />
              <Tooltip contentStyle={{ backgroundColor: '#1e293b', border: '1px solid #475569', borderRadius: 8 }} labelFormatter={v => `Trade #${v}`} formatter={(v: number, name: string) => [`$${v.toFixed(2)}`, name]} />
              <Legend />
              {comparisonKeys.map(key => (
                <Line key={key} type="monotone" dataKey={key} stroke={KELLY_COLORS[key.replace('%', '')] || '#a78bfa'} strokeWidth={2} dot={false} />
              ))}
            </LineChart>
          </ResponsiveContainer>
        </div>
      )}

      {/* Scenario table */}
      <div className="bg-slate-800 rounded-xl border border-slate-700 overflow-hidden">
        <div className="px-5 py-3 border-b border-slate-700">
          <h3 className="text-sm font-medium text-slate-300">All Scenarios ({sortedScenarios.length})</h3>
        </div>
        <div className="overflow-x-auto">
          <table className="w-full text-sm">
            <thead>
              <tr className="text-slate-400 text-xs border-b border-slate-700">
                {([
                  ['kellyFraction', 'Kelly %'],
                  ['startingBankroll', 'Bankroll'],
                  ['finalBankroll', 'Final $'],
                  ['roi', 'Growth %'],
                  ['maxDrawdownPct', 'Max DD %'],
                  ['sharpeRatio', 'Sharpe'],
                ] as [SortKey, string][]).map(([key, label]) => (
                  <th key={key} className="px-4 py-2 text-left cursor-pointer hover:text-white transition-colors" onClick={() => handleSort(key)}>
                    {label} {sortKey === key ? (sortAsc ? '▲' : '▼') : ''}
                  </th>
                ))}
                <th className="px-4 py-2 text-left">Ruined</th>
                <th className="px-4 py-2 text-left">Capped</th>
              </tr>
            </thead>
            <tbody>
              {sortedScenarios.map((s, i) => {
                const rowColor = s.ruined
                  ? 'bg-red-900/20'
                  : s.sharpeRatio > 1 && s.maxDrawdownPct < 0.2
                    ? 'bg-emerald-900/20'
                    : ''
                return (
                  <tr key={i} className={`border-b border-slate-700/50 ${rowColor} hover:bg-slate-700/30 transition-colors`}>
                    <td className="px-4 py-2 font-mono">{(s.kellyFraction * 100).toFixed(0)}%</td>
                    <td className="px-4 py-2 font-mono">${s.startingBankroll.toLocaleString()}</td>
                    <td className={`px-4 py-2 font-mono ${s.finalBankroll >= s.startingBankroll ? 'text-emerald-400' : 'text-red-400'}`}>
                      ${s.finalBankroll.toLocaleString()}
                    </td>
                    <td className={`px-4 py-2 font-mono ${s.roi >= 0 ? 'text-emerald-400' : 'text-red-400'}`}>
                      {(s.roi * 100).toFixed(1)}%
                    </td>
                    <td className={`px-4 py-2 font-mono ${s.maxDrawdownPct > 0.3 ? 'text-red-400' : s.maxDrawdownPct > 0.15 ? 'text-amber-400' : 'text-emerald-400'}`}>
                      {(s.maxDrawdownPct * 100).toFixed(1)}%
                    </td>
                    <td className={`px-4 py-2 font-mono ${s.sharpeRatio > 1 ? 'text-emerald-400' : s.sharpeRatio > 0.5 ? 'text-amber-400' : 'text-red-400'}`}>
                      {s.sharpeRatio.toFixed(3)}
                    </td>
                    <td className="px-4 py-2">{s.ruined ? <span className="text-red-400">YES</span> : <span className="text-slate-500">no</span>}</td>
                    <td className="px-4 py-2">{s.capped ? <span className="text-sky-400">yes</span> : <span className="text-slate-500">no</span>}</td>
                  </tr>
                )
              })}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  )
}

