40	export const DAILY_LOSS_LIMIT = parseFloat(process.env.DAILY_LOSS_LIMIT || '300');
41	
42	const PAPER_BANKROLL = 1000;      // simulated bankroll for Kelly sizing
43	const KELLY_FRACTION = 0.5;     // half-Kelly for safety
44	const MIN_CONTRACTS = 5;
45	const MAX_CONTRACTS = 50;
46	
47	/**
48	 * Estimate win probability based on edge (gap) and model spread.
49	 */
50	function estimateWinProbability(gapF: number, spread: number | null): number {
51	  const absGap = Math.abs(gapF);
52	  const s = spread ?? 999; // treat unknown spread as low confidence
53	
54	  if (absGap >= 5 && s <= 2) return 0.72;
55	  if (absGap >= 3 && s <= 2) return 0.65;
56	  if (absGap >= 3 && s <= 4) return 0.58;
57	  if (absGap >= 2 && s <= 2) return 0.60;
58	  return 0.55;
59	}
60	
61	/**
62	 * Calculate half-Kelly position size.
63	 * Returns { contracts, kellyFraction } or null if no edge (negative Kelly).
64	 */
65	function kellySize(entryPrice: number, gapF: number, spread: number | null, pWinOverride?: number): { contracts: number; kellyFraction: number } | null {
66	  const pWin = pWinOverride ?? estimateWinProbability(gapF, spread);
67	  const odds = (1 / entryPrice) - 1; // net odds (e.g. price=0.40 → odds=1.5)
68	  const kellyFraction = (pWin * odds - (1 - pWin)) / odds;
69	
70	  if (kellyFraction <= 0) return null; // no edge — skip trade
71	
72	  const halfKelly = kellyFraction * KELLY_FRACTION;
73	  const dollarSize = halfKelly * PAPER_BANKROLL;
74	  const contracts = Math.floor(dollarSize / entryPrice);
75	  const clamped = Math.max(MIN_CONTRACTS, Math.min(MAX_CONTRACTS, contracts));
76	
77	  return { contracts: clamped, kellyFraction };
78	}
